import { renderHook } from "#test/browser"
import { useMounted } from "."

describe("useMounted", () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  test("should return true after component is mounted and false after unmount", async () => {
    const { result, unmount } = await renderHook(() => useMounted())
    expect(result.current()).toBeTruthy()
    unmount()
    expect(result.current()).toBeFalsy()
  })

  test("should return mounted state when state is true", async () => {
    const { result } = await renderHook(() => useMounted({ state: true }))

    expect(result.current).toBeTruthy()
  })

  test("should return mounted state with delay when state is true and delay is set", async () => {
    const { act, result } = await renderHook(() =>
      useMounted({ delay: 50, state: true }),
    )

    expect(result.current).toBeFalsy()

    await act(() => vi.advanceTimersByTime(50))

    expect(result.current).toBeTruthy()
  })
})

"use client"

import { useCallback, useRef, useState } from "react"
import { useSafeLayoutEffect } from "@yamada-ui/react"

export interface UseMountedProps {
  delay?: number
  state?: boolean
}

export function useMounted(props?: {
  delay?: number
  state?: false
}): () => boolean

export function useMounted(props?: { delay?: number; state?: true }): boolean

export function useMounted({ delay = 0, state = false }: UseMountedProps = {}) {
  const mountedRef = useRef(false)
  const [mounted, setMounted] = useState(false)

  useSafeLayoutEffect(() => {
    mountedRef.current = true

    let timeoutId: NodeJS.Timeout | null = null

    if (state) {
      if (delay > 0) {
        timeoutId = setTimeout(() => setMounted(true), delay)
      } else {
        setMounted(true)
      }
    }

    return () => {
      mountedRef.current = false

      if (state) setMounted(false)

      if (timeoutId) clearTimeout(timeoutId)
    }
  }, [delay, state])

  if (state) {
    return mounted
  } else {
    return useCallback(() => mountedRef.current, [])
  }
}

export type UseMountedReturn = ReturnType<typeof useMounted>
